INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('34e1943f-e3aa-410a-8ffa-3568eb163139', 'Breaking News', 'Time-sensitive developing stories', '#DC2626', '🔥', '{"pattern":"[What happened] + [where/who] + [significance]","example":"EU passes landmark AI regulation requiring model transparency for all consumer applications","whenToUse":"Use for time-sensitive stories with immediate impact that require urgent publication","contentHints":"Lead with the most important fact. Use inverted pyramid structure. Include quotes, sourcing, and context for significance."}', 1, 0, '2026-03-20T09:03:19.752Z', '2026-03-20T09:03:19.752Z');
