INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('2b987adf-5e02-47fd-8228-26864a4f9f63', 'Opinion', 'Analysis, commentary, and editorial perspectives', '#8B5CF6', '💬', '{"pattern":"[Thesis/position] + [on what topic] + [why it matters]","example":"Remote work mandates are killing innovation — here is what the data actually shows","whenToUse":"Use for editorial commentary, analysis pieces, and opinion columns with a clear thesis","contentHints":"State the thesis upfront. Support with evidence, data, or expert quotes. Acknowledge counterarguments. End with a call to action or forward-looking statement."}', 1, 1, '2026-03-20T09:03:19.752Z', '2026-03-20T09:03:19.752Z');
