INSERT OR IGNORE INTO `item_types` (`id`, `name`, `description`, `color`, `icon`, `guidance`, `is_system`, `sort_order`, `created_at`, `updated_at`) VALUES ('d1d8cfdd-8583-40bd-8277-59f4330c8db7', 'Feature', 'In-depth narrative stories and long-form reporting', '#3B82F6', '📰', '{"pattern":"[Narrative hook] + [subject] + [angle or revelation]","example":"Inside the lab where engineers are teaching robots to feel — and why it could change elder care","whenToUse":"Use for long-form narrative journalism, in-depth profiles, or investigative features","contentHints":"Open with a compelling scene or anecdote. Weave narrative with reporting. Use subheadings to break up long sections. Include sidebars for context."}', 1, 2, '2026-03-20T09:03:19.752Z', '2026-03-20T09:03:19.752Z');
