INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Magazine', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'News, features, and in-depth reporting', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Write a compelling headline. Lead with the most newsworthy element. Avoid clickbait — be specific about the story."},"content":{"tips":"Use inverted pyramid for news, narrative structure for features. Always attribute sources. Include context for why the story matters now."},"formatting":["Headings: break long features into sections with subheads","Block quotes: direct quotes from sources and subjects","Bold: key facts, names on first mention, and data points","Bullet lists: key takeaways, timeline of events","Paragraphs: narrative flow with short, punchy paragraphs","Horizontal rules: separate major sections in long features"],"avoid":["Clickbait headlines that overpromise","Unattributed claims or anonymous sourcing without explanation","Burying the lede below background context","Editorializing in news stories (save for Opinion type)"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":15,"max":200},"content":{"min":200,"max":30000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
